drop extension if exists "pg_net";


  create table "public"."climb_images" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "climb_id" bigint,
    "url" text
      );


alter table "public"."climb_images" enable row level security;


  create table "public"."climb_videos" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "climb_id" bigint,
    "user_id" uuid,
    "url" text
      );


alter table "public"."climb_videos" enable row level security;


  create table "public"."climbs" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "name" text,
    "grade" text,
    "city" text,
    "area" text,
    "subArea" text,
    "slug" text generated always as (lower(regexp_replace(name, '[^a-zA-Z0-9]+'::text, '-'::text, 'g'::text))) stored,
    "type" text
      );


alter table "public"."climbs" enable row level security;


  create table "public"."favorites" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "climb_id" bigint,
    "user_id" uuid
      );


alter table "public"."favorites" enable row level security;


  create table "public"."notes" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "climb_id" bigint,
    "user_id" uuid,
    "note" text
      );


alter table "public"."notes" enable row level security;


  create table "public"."post_images" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "url" text,
    "post_id" bigint
      );


alter table "public"."post_images" enable row level security;


  create table "public"."post_videos" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "post_id" bigint,
    "url" text
      );


alter table "public"."post_videos" enable row level security;


  create table "public"."posts" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "title" text,
    "content" text
      );


alter table "public"."posts" enable row level security;


  create table "public"."profiles" (
    "id" uuid not null,
    "username" text,
    "role" text default 'user'::text,
    "avatar_url" text,
    "created_at" timestamp without time zone default now(),
    "email" text
      );


alter table "public"."profiles" enable row level security;


  create table "public"."sends" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "user_id" uuid,
    "climb_id" bigint
      );


alter table "public"."sends" enable row level security;

CREATE UNIQUE INDEX "Posts_pkey" ON public.posts USING btree (id);

CREATE UNIQUE INDEX climb_images_pkey ON public.climb_images USING btree (id);

CREATE UNIQUE INDEX climb_videos_pkey ON public.climb_videos USING btree (id);

CREATE UNIQUE INDEX climbs_pkey ON public.climbs USING btree (id);

CREATE UNIQUE INDEX climbs_unique_all ON public.climbs USING btree (name, type, grade, city, area, "subArea", slug);

CREATE UNIQUE INDEX favorites_pkey ON public.favorites USING btree (id);

CREATE UNIQUE INDEX notes_pkey ON public.notes USING btree (id);

CREATE UNIQUE INDEX "postImages_pkey" ON public.post_images USING btree (id);

CREATE UNIQUE INDEX post_videos_pkey ON public.post_videos USING btree (id);

CREATE UNIQUE INDEX profiles_pkey ON public.profiles USING btree (id);

CREATE UNIQUE INDEX profiles_username_key ON public.profiles USING btree (username);

CREATE UNIQUE INDEX sends_pkey ON public.sends USING btree (id);

