alter table "public"."climbs" add constraint "climbs_unique_all" UNIQUE using index "climbs_unique_all";

alter table "public"."favorites" add constraint "favorites_climb_id_fkey" FOREIGN KEY (climb_id) REFERENCES public.climbs(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."favorites" validate constraint "favorites_climb_id_fkey";

alter table "public"."favorites" add constraint "favorites_user_id_fkey" FOREIGN KEY (user_id) REFERENCES public.profiles(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."favorites" validate constraint "favorites_user_id_fkey";

alter table "public"."notes" add constraint "notes_climbId_fkey" FOREIGN KEY (climb_id) REFERENCES public.climbs(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."notes" validate constraint "notes_climbId_fkey";

