alter table "public"."post_images" add constraint "postImages_post_id_fkey" FOREIGN KEY (post_id) REFERENCES public.posts(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."post_images" validate constraint "postImages_post_id_fkey";

